const params = {
  email: String,
  senha: String
}

const handler = async (ctx, args) => {
  const result = await ctx.faaskit.run("faas_login", {
    email: args.email,
    senha: args.senha
  })

  if (result.sucesso) {
    ctx.storage.set("usuarioLogado", result.usuario)
    ctx.router.navigate("/home")
  } else {
    ctx.alert(result.error)
  }
}

module.exports = { params, handler }

const params = {
  id_pet: String,
  id_tipo_servico: String,
  id_servico: String,
  data: String,
  observacoes: String
}

const handler = async (ctx, args) => {
  const usuario = ctx.storage.get("usuarioLogado")

  const result = await ctx.faaskit.run("faas_atendimento_create", {
    id_cliente: usuario.id,
    id_pet: args.id_pet,
    id_tipo_servico: args.id_tipo_servico,
    id_servico: args.id_servico,
    data: args.data,
    observacoes: args.observacoes
  })

  if (result.sucesso) {
    ctx.alert("Agendamento criado com sucesso!")
    ctx.router.navigate("/home")
  } else {
    ctx.alert(result.mensagem || result.error)
  }
}

module.exports = { params, handler }

